#include <bits/stdc++.h>
using namespace std;
int mx=-99999999,n,d,a[1005][1005],s[1005][1005];
int main() {
	cin>>n;
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			cin>>a[i][j];
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			for(int k=i; k<=n; k++) {
				for(int l=j; l<=n; l++) {
					if((s[k][l]-s[k][j-1]-s[i-1][l]+s[i-1][j-1])>mx) {
						mx=s[k][l]-s[k][j-1]-s[i-1][l]+s[i-1][j-1];
					}
				}
			}
		}
	}
	cout<<mx;
	return 0;
}
